--
-- Table structure for table `buk_jerarquia`
--

DROP TABLE IF EXISTS `buk_jerarquia`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `buk_jerarquia` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `profundidad` tinyint(4) NOT NULL,
  `tipo_origen_adp` enum('division','centro_costo','unidad') NOT NULL,
  `codigo_adp` varchar(64) NOT NULL,
  `nombre` varchar(255) NOT NULL,
  `parent_div_code` varchar(64) NOT NULL DEFAULT '',
  `parent_cc_code` varchar(64) NOT NULL DEFAULT '',
  `buk_area_id` int(11) DEFAULT NULL,
  `buk_parent_id` int(11) DEFAULT NULL,
  `estado` enum('pendiente','mapeado','sin_equivalencia') NOT NULL DEFAULT 'pendiente',
  `observacion` varchar(255) DEFAULT NULL,
  `last_endpoint` varchar(255) DEFAULT NULL,
  `last_payload` mediumtext DEFAULT NULL,
  `last_response` mediumtext DEFAULT NULL,
  `last_http_code` int(11) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_node` (`profundidad`,`tipo_origen_adp`,`codigo_adp`,`parent_div_code`,`parent_cc_code`),
  KEY `idx_estado` (`estado`),
  KEY `idx_tree` (`profundidad`,`parent_div_code`,`parent_cc_code`),
  KEY `idx_buk` (`buk_area_id`)
) ENGINE=InnoDB AUTO_INCREMENT=12310 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
