--
-- Table structure for table `buk_liq_job_items`
--

DROP TABLE IF EXISTS `buk_liq_job_items`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `buk_liq_job_items` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `job_id` int(11) NOT NULL,
  `rut_norm` varchar(12) NOT NULL,
  `ames` varchar(6) NOT NULL,
  `buk_emp_id` int(11) DEFAULT NULL,
  `nombre` varchar(150) DEFAULT NULL,
  `cargo` varchar(150) DEFAULT NULL,
  `ubicacion` varchar(150) DEFAULT NULL,
  `ccosto` varchar(150) DEFAULT NULL,
  `fecha_ingreso` varchar(30) DEFAULT NULL,
  `dias` varchar(20) DEFAULT NULL,
  `zona` varchar(120) DEFAULT NULL,
  `forma_pago` varchar(120) DEFAULT NULL,
  `banco` varchar(120) DEFAULT NULL,
  `cta` varchar(120) DEFAULT NULL,
  `neto` decimal(12,2) NOT NULL DEFAULT 0.00,
  `pdf_path` varchar(700) DEFAULT NULL,
  `pdf_ok` tinyint(1) NOT NULL DEFAULT 0,
  `pdf_error` mediumtext DEFAULT NULL,
  `visible` tinyint(1) NOT NULL DEFAULT 0,
  `signable` tinyint(1) NOT NULL DEFAULT 0,
  `http_code` int(11) DEFAULT NULL,
  `send_ok` tinyint(1) NOT NULL DEFAULT 0,
  `response_body` mediumtext DEFAULT NULL,
  `updated_at` datetime NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_job_rut` (`job_id`,`rut_norm`),
  KEY `idx_job` (`job_id`),
  KEY `idx_job_pdf` (`job_id`,`pdf_ok`),
  KEY `idx_job_send` (`job_id`,`send_ok`)
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

