DROP TABLE IF EXISTS `stisoft_cambios_queue`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `stisoft_cambios_queue` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `source_file` varchar(255) NOT NULL,
  `source_line` int(11) NOT NULL DEFAULT 0,
  `rut_csv` varchar(32) NOT NULL,
  `rut_bd` varchar(32) NOT NULL,
  `payload_hash` varchar(64) NOT NULL,
  `payload_profile` longtext DEFAULT NULL,
  `payload_plan` longtext DEFAULT NULL,
  `payload_job` longtext DEFAULT NULL,
  `db_updates` longtext DEFAULT NULL,
  `meta_json` longtext DEFAULT NULL,
  `warnings_json` longtext DEFAULT NULL,
  `status` varchar(16) NOT NULL DEFAULT 'pending',
  `attempts` int(11) NOT NULL DEFAULT 0,
  `last_http` int(11) DEFAULT NULL,
  `last_stage` varchar(32) DEFAULT NULL,
  `last_error` text DEFAULT NULL,
  `last_response` longtext DEFAULT NULL,
  `sent_at` datetime DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `updated_at` datetime NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_source_line` (`source_file`,`source_line`),
  UNIQUE KEY `uq_rut_payload` (`rut_bd`,`payload_hash`),
  KEY `idx_status_attempts` (`status`,`attempts`),
  KEY `idx_rut_bd` (`rut_bd`)
) ENGINE=InnoDB AUTO_INCREMENT=850 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
